// HasBomHeader applies the HasEdge predicate on the "bom_header" edge.
func HasBomHeader() predicate.BOMItem {
	return predicate.BOMItem(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.M2O, true, BomHeaderTable, BomHeaderColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasBomHeaderWith applies the HasEdge predicate on the "bom_header" edge with a given conditions (other predicates).
func HasBomHeaderWith(preds ...predicate.BOMHeader) predicate.BOMItem {
	return predicate.BOMItem(func(s *sql.Selector) {
		step := newBomHeaderStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

